const s="http://sandbox-glazed.lndo.site";async function l(){const o=document.getElementById("nodes-list");try{const t=await fetch(`${s}/jsonapi/node/basic_page_layout_builder`);if(!t.ok)throw new Error(`HTTP ${t.status}`);const{data:e}=await t.json();o.innerHTML=e.length?e.map(n=>`<li>${n.attributes.title}</li>`).join(""):'<li style="color:#999">No pages found.</li>'}catch(t){o.innerHTML=`<li style="color:#c00">Could not load: ${t.message}</li>`}}l();